import { createContext, useContext, useContextSelector } from 'use-context-selector';
import { createContextHook } from '@universe-design/react-utilities';
import type { useUpload } from './useUpload';

export type UploadContextType = ReturnType<typeof useUpload> & {
  uploadFiles: (files: File[]) => void;
};
export const {
  Provider: UploadContextProvider,
  useContext: useUploadContext,
  useContextSelector: useUploadContextSelector,
} = createContextHook<UploadContextType>('UploadContext', {
  strict: true,
  customizedContextMethods: {
    createContext,
    useContext,
    useContextSelector,
  },
});
